import { fireEvent, render } from '@testing-library/react-native';
import React from 'react';

import Modal from '../../../src/atomic/atoms/Modal';

describe('atoms/Modal', () => {
  it('should render without errors', () => {
    const close = jest.fn();
    const next = jest.fn();

    const sut = render(
      <Modal
        icon="icon-card-plus"
        value="Value Text"
        title="Testing"
        description="this is a description"
        next={next}
        visible
        close={close}
      />,
    );

    expect(sut).toBeDefined();
  });

  it('should handle events', () => {
    const close = jest.fn();
    const next = jest.fn();

    const sut = render(
      <Modal
        icon="icon-card-plus"
        value="Value Text"
        title="Testing"
        description="this is a description"
        next={next}
        visible
        close={close}
      />,
    );

    const btnClose = sut.getByTestId('btn-close');
    fireEvent.press(btnClose);
    expect(close).toHaveBeenCalled();

    const btnNext = sut.getByTestId('btn-next');
    fireEvent.press(btnNext);
    expect(next).toHaveBeenCalled();
  });
});
